import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installing-mods.gZ3xnRXE.js";const a=JSON.parse(`{"title":"Mods installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Mods für Fabric.","frontmatter":{"title":"Mods installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Mods für Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"de_de/1.21.8/players/installing-mods.md","filePath":"versions/1.21.8/translated/de_de/players/installing-mods.md","lastUpdated":1760721669000}`);var o={name:`de_de/1.21.8/players/installing-mods.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Mods installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Mods installieren”">​</a></h1><p>Diese Anleitung wird die Installation von Mods für Fabric detailliert für den Minecraft-Launcher erklären.</p><p>Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><h2 id="1-download-the-mod" tabindex="-1">1. Herunterladen der Mod <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. Herunterladen der Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Du solltest Mods nur aus Quellen herunterladen, denen du vertraust. Weitere Informationen zum Finden von Mods findest du iim Leitfaden <a href="./finding-mods">Vertrauenswürdige Mods finden</a>.</p></div><p>Die meisten Mods benötigen auch die Fabric API, die von <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> oder <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a> heruntergeladen werden kann.</p><p>Stelle beim Herunterladen von Mods sicher, dass:</p><ul><li>Sie auf der Version von Minecraft funktionieren, auf der du spielen möchtest. Eine Mod, die beispielsweise auf der Version 1.20 funktioniert, muss nicht auf der Version 1.20.2 funktionieren.</li><li>Sie für Fabric sind und nicht für einen anderen Mod-Loader.</li><li>Sie für die korrekte Edition von Minecraft sind (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Verschieben der Mod in das Verzeichnis <code>mods</code> <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Verschieben der Mod in das Verzeichnis mods”">​</a></h2><p>Das Mods-Verzeichnis kann, abhängig vom Betriebssystem, an den folgenden Stellen gefunden werden.</p><p>Normalerweise können die Pfade direkt in der Adressleiste des Dateiexplorers eingefügt werden, um schnell zum Verzeichnis zu navigieren.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Sobald du das <code>mods</code>-Verzeichnis gefunden hast, kannst du die <code>.jar</code>-Dateien der Mods dorthin verschieben.</p><p><img src="/assets/players/installing-mods.png" alt="Installierte Mods im mods-Verzeichnis" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. Du hast es geschafft! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Du hast es geschafft!”">​</a></h2><p>Sobald du die Mods in das <code>mods</code>-Verzeichnis verschoben hast, kannst du den Minecraft-Launcher öffnen und das Fabric-Profil aus der Liste in der unteren linken Ecke auswählen und spielen!</p><p>Sobald du die Mods in das <code>mods</code>-Verzeichnis verschoben hast, kannst du den Minecraft-Launcher öffnen und das Fabric-Profil aus der Liste in der unteren linken Ecke auswählen und spielen!</p><h2 id="troubleshooting" tabindex="-1">Problembehandlung <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Problembehandlung”">​</a></h2><p>Fall dir beim Folgen dieser Anleitungen irgendwelche Fehler auftreten, kannst du nach Hilfe im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric-Discord</a> im Kanal <code>#player-support</code> fragen.</p><p>Du kannst auch versuchen, das Problem mit diesen Fehlerbehebungs-Seiten selbst zu lösen:</p><ul><li><a href="./troubleshooting/crash-reports">Absturzberichte</a></li><li><a href="./troubleshooting/uploading-logs">Logs hochladen</a></li></ul>`,21)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};